1	\chapter{Local Iwasawa Selmer}
2	\label{chap:local-iwasawa-selmer}
3	
4	% archon:covers MR4372220OnTheAnticyclotomicIwasawaTheoryOfRationalEllipticCurvesAtEisensteinPrimes/Local.lean
5	
6	This chapter fixes the local anticyclotomic Iwasawa notation once, packages the character Selmer groups as kernels of localisation maps, and isolates the split and \(p\)-adic local cohomology input needed later by the algebraic and Howard branches.
7	
8	\begin{definition}[Iwasawa algebra and Selmer structures]
9	  \label{def:iwasawa-algebra}
10	  \lean{MR4372220.Local.iwasawaAlgebra}
11	  % SOURCE: [Castella--Grossi--Lee--Skinner, Local cohomology groups of characters; Selmer groups of characters; Local cohomology groups of E; Selmer groups of E] (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
12	  % SOURCE QUOTE: "Set \(M_\theta=\Z_p(\theta)\otimes_{\Z_p}\Lambda^\vee\),"
13	  \textit{Source: Castella--Grossi--Lee--Skinner, Local cohomology groups of characters; Selmer groups of characters; Local cohomology groups of E; Selmer groups of E.}
14	  Let \(\Gamma = \mathrm{Gal}(K_\infty/K)\) and \(\Lambda = \mathbb{Z}_p\llbracket \Gamma\rrbracket\), and write \(\Lambda^{\mathrm{ur}} = \Lambda \widehat{\otimes}_{\mathbb{Z}_p}\mathbb{Z}_p^{\mathrm{ur}}\).
15	  For a character \(\theta : G_K \to \mathbb{F}_p^\times\), set
16	  \[
17	    M_\theta = \mathbb{Z}_p(\theta)\otimes_{\mathbb{Z}_p}\Lambda^\vee,
18	  \]
19	  where \(\Lambda^\vee = \operatorname{Hom}_{\mathrm{cts}}(\Lambda,\mathbb{Q}_p/\mathbb{Z}_p)\), and for an elliptic curve \(E/\mathbb{Q}\) of good reduction at \(p\), set
20	  \[
21	    M_E = T_pE\otimes_{\mathbb{Z}_p}\Lambda^\vee.
22	  \]
23	  For a finite set \(\Sigma\) of places of \(K\) containing \(\infty\), the places above \(p\), the primes dividing the relevant conductor, and all finite places split in \(K\), define the Greenberg Selmer group by the kernel of the usual global-to-local map
24	  \[
25	    H^1_{\mathcal{F}_{\mathrm{Gr}}}(K,M_\theta)
26	    = \ker\!\left(H^1(K^\Sigma/K,M_\theta)\to \prod_{w\in\Sigma,\;w\nmid p} H^1(K_w,M_\theta)\times H^1(K_{\bar v},M_\theta)\right),
27	  \]
28	  and the \(S\)-imprimitive variant, where \(S=\Sigma\setminus\{v,\bar v,\infty\}\), by
29	  \[
30	    H^1_{\mathcal{F}_{\mathrm{Gr}}^S}(K,M_\theta)
31	    = \ker\!\left(H^1(K^\Sigma/K,M_\theta)\to H^1(K_{\bar v},M_\theta)\right).
32	  \]
33	  Replacing \(M_\theta\) with \(M_\theta[p]\) gives the residual character Selmer groups \(H^1_{\mathcal{F}_{\mathrm{Gr}}}(K,M_\theta[p])\) and \(H^1_{\mathcal{F}_{\mathrm{Gr}}^S}(K,M_\theta[p])\). Their Pontryagin duals are denoted \(\mathfrak{X}_\theta\) and \(\mathfrak{X}_\theta^S\). The corresponding primitive and \(S\)-imprimitive Selmer groups for \(M_E\) are defined by the same kernel conditions, but this chapter does not enter the \(M_E[p]\) comparison theory.
34	\end{definition}
35	
36	\begin{lemma}[Commutative algebra criterion]
37	  \label{lem:commalg}
38	  \lean{MR4372220.Local.commAlgCriterion}
39	  \uses{def:iwasawa-algebra}
40	  % SOURCE: [Castella--Grossi--Lee--Skinner, Local cohomology groups of characters, \(w\mid p\)] (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
41	  % SOURCE QUOTE: "a free \(\Lambda\)-module"
42	  \textit{Source: Castella--Grossi--Lee--Skinner, Local cohomology groups of characters, \(w\mid p\).}
43	  Let \(X\) be a finitely generated \(\Lambda\)-module. If \(X[T]=0\) and \(X/TX\) is a free \(\mathbb{Z}_p\)-module of rank \(r\), then \(X\) is a free \(\Lambda\)-module of rank \(r\).
44	\end{lemma}
45	
46	\begin{proof}
47	Use Nakayama to produce a surjection \(\Lambda^r\twoheadrightarrow X\), then compare modulo \(T\). The condition \(X[T]=0\) kills the kernel after reduction, and a second Nakayama argument shows that the kernel is already zero.
48	\end{proof}
49	
50	For \(w\nmid p\) split in \(K\), write \(\mathcal{P}_w(\theta)\in\Lambda\) for the Euler factor attached to \(w\).
51	
52	\begin{lemma}[Split local cohomology away from \(p\)]
53	  \label{lem:local-char-wneqp}
54	  \lean{MR4372220.Local.localCohomologySplit}
55	  \uses{def:iwasawa-algebra}
56	  % SOURCE: [Castella--Grossi--Lee--Skinner, Local cohomology groups of characters, \(w\nmid p\) split in \(K\)] (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
57	  % SOURCE QUOTE: "char_\Lambda(\rH^1(K_w,M_\theta)^\vee)=(\mathcal{P}_w(\theta))"
58	  \textit{Source: Castella--Grossi--Lee--Skinner, Local cohomology groups of characters, \(w\nmid p\) split in \(K\).}
59	  For a prime \(w\nmid p\) split in \(K\), the local dual \(H^1(K_w,M_\theta)^\vee\) is \(\Lambda\)-torsion with characteristic ideal generated by \(\mathcal{P}_w(\theta)\). In particular, \(H^1(K_w,M_\theta)^\vee\) has \(\mu=0\).
60	\end{lemma}
61	
62	\begin{proof}
63	The key point is that \(w\) is finitely decomposed in \(K_\infty/K\), so the local cohomology is governed by the unramified quotient of inertia. The characteristic ideal is the local Euler factor, and therefore no nontrivial \(\mu\)-part can appear.
64	\end{proof}
65	
66	\begin{proposition}[Local cohomology at \(p\)]
67	  \label{lem:local-char-wp}
68	  \lean{MR4372220.Local.localCohomologyAtP}
69	  \uses{def:iwasawa-algebra, lem:commalg}
70	  % SOURCE: [Castella--Grossi--Lee--Skinner, Local cohomology groups of characters, \(w\mid p\)] (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
71	  % SOURCE QUOTE: "\(\Lambda\)-cofree of rank \(1\)"
72	  \textit{Source: Castella--Grossi--Lee--Skinner, Local cohomology groups of characters, \(w\mid p\).}
73	  Let \(\omega : G_{\mathbb{Q}}\to \mathbb{F}_p^\times\) be the mod \(p\) cyclotomic character, and let \(w\mid p\) be a place of \(K\). If \(\theta|_{G_w}\neq 1,\omega\), then the restriction map
74	  \[
75	    H^1(K_w,M_\theta)\to H^1(I_w,M_\theta)^{G_w/I_w}
76	  \]
77	  is an isomorphism, and \(H^1(K_w,M_\theta)\) is \(\Lambda\)-cofree of rank \(1\).
78	\end{proposition}
79	
80	\begin{proof}
81	Injectivity comes from the vanishing of \(M_\theta^{G_w}\), and the cofree statement is reduced to a rank computation for the Pontryagin dual. The quotient by \(T\) vanishes on the character module, so \cref{lem:commalg} applies after local duality and the local Euler characteristic formula.
82	\end{proof}
83	
84	\begin{theorem}[Rubin--Hida \(\mu=0\) theorem]
85	  \label{thm:mu-zero-theta}
86	  \lean{MR4372220.Local.muZeroTheta}
87	  \uses{def:iwasawa-algebra, lem:local-char-wneqp, lem:local-char-wp}
88	  % SOURCE: [Castella--Grossi--Lee--Skinner, Selmer groups of characters] (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
89	  % SOURCE QUOTE: "torsion \(\Lambda\)-module with \(\mu\)-invariant zero"
90	  \textit{Source: Castella--Grossi--Lee--Skinner, Selmer groups of characters.}
91	  If \(\theta|_{G_{\bar v}}\neq 1,\omega\), then \(\mathfrak{X}_\theta\) is a torsion \(\Lambda\)-module with \(\mu=0\).
92	\end{theorem}
93	
94	\begin{proof}
95	Identify the Selmer group with the \(\theta\)-isotypic component of the relevant anticyclotomic class group by Shapiro's lemma and class field theory. Rubin's main-conjecture input gives the characteristic ideal, and Hida's vanishing of the \(\mu\)-invariant for the Katz \(p\)-adic \(L\)-function gives the conclusion.
96	\end{proof}
97	
98	\begin{proposition}[Imprimitive \(\lambda\)-formula]
99	  \label{prop:lambda-theta}
100	  \lean{MR4372220.Local.lambdaTheta}
101	  \uses{def:iwasawa-algebra, thm:mu-zero-theta, lem:local-char-wneqp, lem:local-char-wp}
102	  % SOURCE: [Castella--Grossi--Lee--Skinner, Selmer groups of characters] (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
103	  % SOURCE QUOTE: "has no nonzero pseudo-null"
104	  \textit{Source: Castella--Grossi--Lee--Skinner, Selmer groups of characters.}
105	  If \(\theta|_{G_{\bar v}}\neq 1,\omega\), then \(\mathfrak{X}_\theta^S\) is a torsion \(\Lambda\)-module with \(\mu=0\), and
106	  \[
107	    \lambda(\mathfrak{X}_\theta^S)
108	    = \lambda(\mathfrak{X}_\theta) + \sum_{w\in S,\; w\nmid p}\lambda(\mathcal{P}_w(\theta)).
109	  \]
110	  Moreover, \(H^1_{\mathcal{F}_{\mathrm{Gr}}^S}(K,M_\theta[p])\) is finite and
111	  \[
112	    \dim_{\mathbb{F}_p}\bigl(H^1_{\mathcal{F}_{\mathrm{Gr}}^S}(K,M_\theta[p])\bigr)=\lambda(\mathfrak{X}_\theta^S).
113	  \]
114	\end{proposition}
115	
116	\begin{proof}
117	Compare the primitive and \(S\)-imprimitive Selmer groups by exactness of localisation, then use \cref{thm:mu-zero-theta} and the split-prime local calculation to read off the Euler-factor contribution to \(\lambda\). The absence of nonzero pseudo-null submodules turns the \(\lambda\)-invariant into the size of the residual Selmer group.
118	\end{proof}
119	
120	\begin{corollary}[Residual exactness]
121	  \label{cor:characters}
122	  \lean{MR4372220.Local.charactersResidualExactness}
123	  \uses{def:iwasawa-algebra, prop:lambda-theta, lem:local-char-wp}
124	  % SOURCE: [Castella--Grossi--Lee--Skinner, Corollary \ref{corcharacters}] (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
125	  % SOURCE QUOTE: "is exact"
126	  \textit{Source: Castella--Grossi--Lee--Skinner, Corollary \ref{corcharacters}.}
127	  If \(\theta|_{G_{\bar v}}\neq 1,\omega\), then \(H^2(K^\Sigma/K,M_\theta[p])=0\), and the residual sequence
128	  \[
129	    0\to H^1_{\mathcal{F}_{\mathrm{Gr}}^S}(K,M_\theta[p])\to H^1(K^\Sigma/K,M_\theta[p])\to H^1(K_{\bar v},M_\theta[p])\to 0
130	  \]
131	  is exact.
132	\end{corollary}
133	
134	\begin{proof}
135	The previous proposition gives \(H^2(K^\Sigma/K,M_\theta)=0\), and the short exact sequence induced by multiplication by \(p\) then identifies the residual \(H^2\)-group. Divisibility of the imprimitive Selmer group and the \(\Lambda\)-cofreeness of the local term at \(\bar v\) force the snake-lemma sequence to be exact.
136	\end{proof}
